```java
import javafx.application.Application;
import javafx.scene.control.ButtonType;
import javafx.scene.control.Dialog;
import javafx.stage.Stage;

public class ConfirmDialogExample extends Application {

    @Override
    public void start(Stage primaryStage) {
        // 显示确认对话框
        boolean result = showConfirmationDialog("确认删除", "您确定要删除所选项目吗？");

        // 根据用户的选择进行处理
        if (result) {
            System.out.println("用户确认");
            // 执行删除操作
        } else {
            System.out.println("用户取消");
        }
    }

    private boolean showConfirmationDialog(String title, String content) {
        // 创建一个Dialog实例
        Dialog<ButtonType> dialog = new Dialog<>();
        dialog.setTitle(title);
        dialog.setContentText(content);

        // 添加按钮类型
        dialog.getDialogPane().getButtonTypes().addAll(ButtonType.YES, ButtonType.NO);

        // 显示对话框，并捕获用户响应
        java.util.Optional<ButtonType> response = dialog.showAndWait();

        // 判断用户是否点击了 "YES" 按钮
        return response.isPresent() && response.get() == ButtonType.YES;
    }

    public static void main(String[] args) {
        launch(args);
    }
}
```

这段代码演示了如何创建一个基本的确认对话框，询问用户是否确认要执行某个动作（比如删除），并根据用户的选择（"YES" 或 "NO"）来决定相应的行为。此示例使用了JavaFX自带的`Dialog`类来创建对话框，并通过添加`ButtonType.YES`和`ButtonType.NO`作为用户的选择按钮。

